from dataclasses import dataclass
from datetime import date, timedelta

@dataclass
class SupportProgramMetrics:
    period_start: date
    period_end: date
    l1_total: int
    l1_escalated_to_l2: int
    l2_total: int
    l2_escalated_to_l3: int
    tickets_kb_surfaced: int
    tickets_kb_helped: int

    def l1_escalation_rate(self) -> float:
        return self.l1_escalated_to_l2 / self.l1_total if self.l1_total else 0.0

    def l2_escalation_rate(self) -> float:
        return self.l2_escalated_to_l3 / self.l2_total if self.l2_total else 0.0

    def kb_deflection_rate(self) -> float:
        return self.tickets_kb_helped / self.tickets_kb_surfaced if self.tickets_kb_surfaced else 0.0

    def health_flags(self) -> list[str]:
        flags = []
        if self.l1_escalation_rate() > 0.30:
            flags.append(f"L1 escalation rate {self.l1_escalation_rate():.0%} > 30% threshold — review KB coverage")
        if self.l2_escalation_rate() > 0.15:
            flags.append(f"L2 escalation rate {self.l2_escalation_rate():.0%} > 15% threshold — review L3 runbooks")
        if self.kb_deflection_rate() < 0.40:
            flags.append(f"KB deflection rate {self.kb_deflection_rate():.0%} < 40% target — review article quality")
        return flags
